SELECT vr_nsk_015_004000.balance_date, vr_nsk_015_004000.membership_no, vr_nsk_015_004000.memname, vr_nsk_015_004000.member_group_no, vr_nsk_015_004000.member_group_name, vr_nsk_015_004000.loan_contract_no, vr_nsk_015_004000.balance_forward, vr_nsk_015_004000.period_miss, vr_nsk_015_004000.int_arrear , vr_nsk_015_004000.loan_code , vr_nsk_015_004000.loan_code_desc FROM vr_nsk_015_004000 ,sc_mem_m_ucf_member_group
where 1=1 and vr_nsk_015_004000.balance_date= to_date('!balance_date!','dd/mm/yyyy') and vr_nsk_015_004000.member_group_no = sc_mem_m_ucf_member_group.member_group_no
/*WHERE*/
